/**
 * Finds the index of the largest element in nums <= X.
 * Returns -1 if all elements are > X.
 * Assumes nums is sorted.
 * @param {number[]} nums 
 * @param {number} X 
 * @returns {number} index
 */
function upper_bound_index(nums, X) {
    let low = 0;
    let high = nums.length - 1;
    let result = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        // Using <= ensures we find the last occurrence of an element <= X
        if (nums[mid] <= X) {
            result = mid; 
            low = mid + 1; 
        } else {
            high = mid - 1; 
        }
    }
    return result;
}


function solve(nums, queries) {
    const N = nums.length;

    // 1. Precompute E_count: E_count[i] = count of even numbers in nums[0..i]
    const E_count = new Array(N);
    let currentCount = 0;
    for (let i = 0; i < N; i++) {
        if (nums[i] % 2 === 0) {
            currentCount++;
        }
        E_count[i] = currentCount;
    }

    const results = [];

    // Maximum possible M we need to check. Since k <= 10^9, M must be at least k. 
    // 2*10^9 + 2 is a safe upper bound.
    const MAX_M = 2000000002; 

    for (const query of queries) {
        const [l, r, k] = query;

        // Binary Search for the smallest M such that M - C(2M) >= k
        let lowM = 1;
        let highM = MAX_M;
        let bestM = MAX_M;

        while (lowM <= highM) {
            const M = Math.floor((lowM + highM) / 2);
            const X = 2 * M;

            // Calculate C(X): count of even numbers in nums[l..r] that are <= X

            // Step 1: Find index j = largest index such that nums[j] <= X
            const j = upper_bound_index(nums, X);

            // Step 2: Determine the effective right boundary R'
            // R' is the intersection of the query range [l, r] and the value range [0, j]
            const R_prime = Math.min(r, j);

            let C_X = 0;
            if (R_prime >= l) {
                // Count even numbers in nums[l..R_prime] using prefix sums
                const countUpToRPrime = E_count[R_prime];

                let countBeforeL = 0;
                if (l > 0) {
                    countBeforeL = E_count[l - 1];
                }

                C_X = countUpToRPrime - countBeforeL;
            }

            // Check the condition: M - C_X >= k
            // M is the total count of even numbers <= X. C_X is the count removed.
            // M - C_X is the count remaining.
            if (M - C_X >= k) {
                // M satisfies the condition, record it and try smaller M
                bestM = M;
                highM = M - 1;
            } else {
                // M is too small, need a larger M
                lowM = M + 1;
            }
        }

        const ans = 2 * bestM;
        results.push(ans);
    }

    return results;
}

