import java.util.ArrayList;
import java.util.List;

public class Solution {

    /**
     * Finds the index of the largest element in nums <= X.
     * Returns -1 if all elements are > X.
     * Assumes nums is sorted.
     * @param nums The sorted array.
     * @param X The target value.
     * @return The largest index j such that nums[j] <= X.
     */
    private static int upperBoundIndex(long[] nums, long X) {
        int low = 0;
        int high = nums.length - 1;
        int result = -1;

        while (low <= high) {
            int mid = low + (high - low) / 2;
            // Using <= ensures we find the last occurrence of an element <= X
            if (nums[mid] <= X) {
                result = mid; 
                low = mid + 1; 
            } else {
                high = mid - 1; 
            }
        }
        return result;
    }

    public static long[] solve(long[] nums, long[][] queries) {
        int N = nums.length;

        // 1. Precompute E_count: E_count[i] = count of even numbers in nums[0..i]
        // Since N <= 10^5, int is sufficient for counts.
        int[] E_count = new int[N];
        int currentCount = 0;
        for (int i = 0; i < N; i++) {
            if (nums[i] % 2 == 0) {
                currentCount++;
            }
            E_count[i] = currentCount;
        }

        List<Long> results = new ArrayList<>();

        // Maximum possible M we need to check. 
        // k <= 10^9. Max M is slightly above k, e.g., 2*10^9 + N/2.
        // Using 2 * 10^9 + 10^5 + 5 as a safe upper bound for M.
        long MAX_M = 2_000_000_000L + N + 5; 

        for (long[] query : queries) {
            long l = query[0];
            long r = query[1];
            long k = query[2];

            // Binary Search for the smallest M such that M - C(2M) >= k
            long lowM = 1;
            long highM = MAX_M;
            long bestM = MAX_M + 1; // Initialize to something larger than possible

            while (lowM <= highM) {
                long M = lowM + (highM - lowM) / 2;
                long X = 2 * M;

                // Calculate C(X): count of even numbers in nums[l..r] that are <= X

                // Step 1: Find index j = largest index such that nums[j] <= X
                int j = upperBoundIndex(nums, X);

                // Step 2: Determine the effective right boundary R_prime
                // R_prime is the intersection of the query range [l, r] and the value range [0, j]
                int R_prime = (int) Math.min(r, (long)j);

                long C_X = 0;
                if (R_prime >= l) {
                    // Count even numbers in nums[l..R_prime] using prefix sums
                    int countUpToRPrime = E_count[R_prime];

                    int countBeforeL = 0;
                    if (l > 0) {
                        countBeforeL = E_count[(int)(l - 1)];
                    }

                    C_X = countUpToRPrime - countBeforeL;
                }

                // Check the condition: M - C_X >= k
                if (M - C_X >= k) {
                    // M satisfies the condition, record it and try smaller M
                    bestM = M;
                    highM = M - 1;
                } else {
                    // M is too small, need a larger M
                    lowM = M + 1;
                }
            }

            long ans = 2 * bestM;
            results.add(ans);
        }

        long[] finalResults = new long[results.size()];
        for (int i = 0; i < results.size(); i++) {
            finalResults[i] = results.get(i);
        }
        return finalResults;
    }
}

